// Parse trends data and combine with manual ideas
const trendsData = $input.first().json;
let trendingTopics = [];

// Try to parse Google Trends response
try {
  if (trendsData && trendsData.body) {
    // Google Trends API returns data with )]}' prefix
    const cleanJson = trendsData.body.replace(")]}'\n", '');
    const parsed = JSON.parse(cleanJson);

    if (parsed.default?.trendingSearchesDays) {
      parsed.default.trendingSearchesDays.forEach(day => {
        day.trendingSearches?.slice(0, 5).forEach(trend => {
          trendingTopics.push({
            title: trend.title?.query || trend.title,
            traffic: trend.formattedTraffic || 'N/A',
            source: 'google_trends'
          });
        });
      });
    }
  }
} catch (e) {
  console.log('Trends parsing failed, using fallback');
}

// If no trends found, use tech topic fallbacks
if (trendingTopics.length === 0) {
  trendingTopics = [
    { title: 'AI tools for productivity', traffic: 'High', source: 'fallback' },
    { title: 'Claude vs ChatGPT comparison', traffic: 'High', source: 'fallback' },
    { title: 'Learn coding with AI', traffic: 'Medium', source: 'fallback' },
    { title: 'Automation for creators', traffic: 'Medium', source: 'fallback' },
    { title: 'Side hustle ideas 2024', traffic: 'High', source: 'fallback' }
  ];
}

// Personal idea bank (add your own ideas here)
const personalIdeas = [
  'How I automate my YouTube workflow',
  'The AI tools I use daily',
  'Building a second brain with Notion',
  'My productivity system explained'
];

return {
  json: {
    trendingTopics: trendingTopics.slice(0, 10),
    personalIdeas: personalIdeas,
    totalIdeas: trendingTopics.length + personalIdeas.length,
    generatedAt: new Date().toISOString()
  }
};

