// Parse Claude's response and format output
const claudeResponse = $input.first().json;
let rankedIdeas = [];

try {
  // Extract the text content from Claude's response
  const content = claudeResponse.content?.[0]?.text || '';

  // Try to parse JSON from the response
  const jsonMatch = content.match(/\[([\s\S]*?)\]/);
  if (jsonMatch) {
    rankedIdeas = JSON.parse(`[${jsonMatch[1]}]`);
  } else {
    // Fallback: create structured output from text
    rankedIdeas = [{
      rank: 1,
      title: 'Could not parse Claude response',
      reasoning: content.substring(0, 200),
      angle: 'Manual review needed',
      difficulty: 'Medium'
    }];
  }
} catch (e) {
  rankedIdeas = [{
    rank: 1,
    title: 'Error parsing response',
    reasoning: String(e),
    angle: 'Check Claude API response',
    difficulty: 'Unknown'
  }];
}

return {
  json: {
    success: true,
    generatedAt: new Date().toISOString(),
    topIdeas: rankedIdeas,
    count: rankedIdeas.length
  }
};
